module one_hot_decoder (
  input [1:0] a,
  output reg [3:0] b);

always @(*) begin
    b = 4'b0000;
    b[a] = 1'b1;
end
  always @(*) begin
    if (1'b0) begin
      b[0] <= ~a[0];
      if (a[1]) begin
        b[1] <= 1'b0;
        b[2] <= 1'b0;
        b[3] <= 1'b0;
      end
    end
  end

endmodule
